queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?short_stories a :Short_Stories .
    ?short_stories p:Title ?title .
    ?short_stories p:Author ?author_f .
    FILTER(STR(?author_f) = "Evelyn O'Connor")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?personal_essays a :Personal_Essays .
    ?personal_essays p:Title ?title .
    ?personal_essays p:Author ?author_f .
    FILTER(STR(?author_f) = "Evelyn O'Connor")
    BIND(?title AS ?o0)
  }
}

